/**
 * WASM AI Module Loader — Mancala
 *
 * Auto-generated BASE64 constant by scripts/build-wasm.js.
 * Run `pnpm wasm:build` to update the binary.
 */

// Auto-generated BASE64 encoding of compiled WASM module
export const AI_WASM_BASE64 =
  ''

let wasmInstance: WebAssembly.Instance | null = null
let wasmMemory: WebAssembly.Memory | null = null

/**
 * Initialize WASM module.
 * Returns true if successful, false if unavailable or failed.
 */
export async function initWasm(): Promise<boolean> {
  if (wasmInstance) {
    return true // Already initialized
  }

  try {
    if (!AI_WASM_BASE64) {
      console.warn('[WASM AI] Module not compiled. Run: pnpm wasm:build')
      return false
    }

    // Decode base64 to bytes
    const binaryString = atob(AI_WASM_BASE64)
    const bytes = new Uint8Array(binaryString.length)
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i)
    }

    // Create WebAssembly memory (1 page = 64KB)
    wasmMemory = new WebAssembly.Memory({ initial: 1 })

    // Instantiate module
    const wasmModule = await WebAssembly.instantiate(bytes, {
      env: {
        memory: wasmMemory,
      },
    })

    wasmInstance = wasmModule.instance
    return true
  } catch (error) {
    console.error('[WASM AI] Failed to initialize:', error)
    wasmInstance = null
    wasmMemory = null
    return false
  }
}

/**
 * Select best move using WASM minimax (fixed ply depth).
 *
 * @param board - 14-element board array (indices 0-13)
 * @param player - Current player (0 or 1)
 * @param depth - Search depth (lookahead plies: 1-6 recommended)
 * @returns Pit index to move from, or -1 if no valid moves
 */
export function selectBestMoveWasm(board: number[], player: number, depth: number): number {
  if (!wasmInstance || !wasmMemory) {
    throw new Error('[WASM AI] Module not initialized. Call initWasm() first.')
  }

  const exports = wasmInstance.exports as Record<
    string,
    (ptr: number, player: number, depth: number) => number
  >
  if (!exports.selectBestMove) {
    throw new Error('[WASM AI] selectBestMove function not found in WASM module.')
  }

  const buffer = new Uint32Array(wasmMemory.buffer)

  // Write board to WASM memory (start at offset 0, 14 u32 values = 56 bytes)
  for (let i = 0; i < 14; i++) {
    buffer[i] = board[i] || 0
  }

  // Call WASM function
  const result = exports.selectBestMove(0, player, depth)

  // 255 = invalid/no moves
  return result === 255 ? -1 : result
}

/**
 * Evaluate board position using WASM heuristic.
 *
 * @param board - 14-element board array
 * @param player - Player to evaluate for (0 or 1)
 * @returns Heuristic score (positive = favorable for player, negative = unfavorable)
 */
export function evaluateBoardWasm(board: number[], player: number): number {
  if (!wasmInstance || !wasmMemory) {
    throw new Error('[WASM AI] Module not initialized. Call initWasm() first.')
  }

  const exports = wasmInstance.exports as Record<string, (ptr: number, player: number) => number>
  if (!exports.evaluateBoardPosition) {
    throw new Error('[WASM AI] evaluateBoardPosition function not found in WASM module.')
  }

  const buffer = new Uint32Array(wasmMemory.buffer)

  // Write board to WASM memory
  for (let i = 0; i < 14; i++) {
    buffer[i] = board[i] || 0
  }

  // Call WASM function and cast result to signed i32
  const result = exports.evaluateBoardPosition(0, player)
  // Convert u32 to i32 if needed
  return result > 2147483647 ? result - 4294967296 : result
}

/**
 * Select best move using iterative deepening with time limit (WASM).
 * Gradually increases lookahead depth until time budget expires.
 *
 * @param board - 14-element board array
 * @param player - Current player (0 or 1)
 * @param timeMs - Time budget in milliseconds (200-2000 recommended)
 * @returns Pit index to move from, or -1 if no valid moves
 */
export function selectBestMoveIterativeWasm(
  board: number[],
  player: number,
  timeMs: number,
): number {
  if (!wasmInstance || !wasmMemory) {
    throw new Error('[WASM AI] Module not initialized. Call initWasm() first.')
  }

  const exports = wasmInstance.exports as Record<
    string,
    (ptr: number, player: number, timeMs: number) => number
  >
  if (!exports.selectBestMoveIterative) {
    throw new Error('[WASM AI] selectBestMoveIterative function not found in WASM module.')
  }

  const buffer = new Uint32Array(wasmMemory.buffer)

  // Write board to WASM memory
  for (let i = 0; i < 14; i++) {
    buffer[i] = board[i] || 0
  }

  // Call WASM function with time budget
  const result = exports.selectBestMoveIterative(0, player, timeMs)

  // 255 = invalid/no moves
  return result === 255 ? -1 : result
}

/**
 * Deprecated: Use selectBestMoveIterativeWasm instead.
 * Kept for backward compatibility.
 */
export function selectMoveIterativeWasm(board: number[], player: number, timeMs: number): number {
  return selectBestMoveIterativeWasm(board, player, timeMs)
}
